public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public Event Event { get; set; }
    public bool IsPurchased { get; set; }
}

public class Program
{
    public static async Task<int> PurchaseTicketsAsync(EventBookingContext context, int eventId, int quantity)
    {
        var eventEntity = await context.Events.FindAsync(eventId);
        if (eventEntity == null || eventEntity.AvailableSeats < quantity)
            return 0;

        try
        {
            await context.Database.ExecuteSqlRawAsync("UPDATE Events SET AvailableSeats = AvailableSeats - @quantity WHERE Id = @eventId", new { quantity, eventId });
            var ticketEntities = new Ticket[] { };
            for (int i = 0; i < quantity; i++)
                ticketEntities.Add(new Ticket { EventId = eventId });

            await context.Tickets.AddRangeAsync(ticketEntities);
            await context.SaveChangesAsync();
        }
        catch (DbUpdateConcurrencyException)
        {
            // Handle concurrency exception
        }

        return quantity;
    }
